<section class="admin-page-head"><div><span class="eyebrow">Fulfillment and sales</span><h1>Orders</h1><p>Online requests and completed POS sales share one history.</p></div><?php if (can('pos.access')): ?><a class="button button-primary" href="<?= url('admin/pos') ?>"><i data-lucide="tablet-smartphone"></i>Open POS</a><?php endif; ?></section>
<section class="admin-panel"><div class="admin-table-wrap"><table class="admin-table"><thead><tr><th>Order</th><th>Customer</th><th>Source</th><th>Payment</th><th>Status</th><th>Total</th><th></th></tr></thead><tbody><?php foreach($orders as $order): ?><tr><td><strong><?= e($order['order_number']) ?></strong><small><?= e(date('M j · g:i A',strtotime($order['created_at']))) ?></small></td><td><strong><?= e($order['customer_name']) ?></strong><small><?= e($order['customer_phone'] ?: 'No phone') ?></small></td><td><span class="status-pill"><?= ($order['order_source'] ?? 'online') === 'pos' ? 'POS' : e(ucfirst($order['fulfillment'])) ?></span></td><td><span class="status-pill"><?= $order['payment_method'] === 'external_card' ? 'External terminal' : e(ucwords(str_replace('_',' ',$order['payment_method']))) ?></span></td><td><span class="status-pill status-<?= e($order['status']) ?>"><?= e(ucwords(str_replace('_',' ',$order['status']))) ?></span></td><td><?= money((int)$order['total_cents']) ?></td><td><a class="icon-button" href="<?= url('admin/orders/'.$order['id']) ?>"><i data-lucide="chevron-right"></i></a></td></tr><?php endforeach; ?></tbody></table></div><?php if(!$orders): ?><div class="empty-state small"><i data-lucide="package-open"></i><h3>No orders yet</h3></div><?php endif; ?></section>
